174	async function fireAndTrace(pod, run, { settleMs = 240_000, quietMs = 20_000 } = {}) {
175	  const before = new Set(await sessionIds(pod));
176	  const res = await run().catch((e) => ({ error: String(e) }));
177	  const t0 = now();
