183	    for (const i of (await sessionIds(pod)).filter((i) => !before.has(i))) seen.add(i);
184	    const drained = await drainSessions(pod, [...seen]);
185	    if (drained.length > events.length) lastGrowth = now();
186	    events = drained;
187	    const list = await pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
188	    const busy = (list.sessions ?? []).some((s) => seen.has(s.sessionId) && s.status !== 'idle');
