624	    'the durable "away last week of August" preference delegates to user-memory; a brand-new, historyless session still recalls it',
625	  );
626	  const t = acc(await timed('Act XII — store the durable preference', () =>
627	    thing.send("Remember this for good: I'm away the last week of August for a craft fair, don't count on me answering anything then.", { timeoutMs: TURN })));
628	  report.check('the preference delegated to user-memory', thing.didDelegate('user-memory') || t.yields.some((y) => /memor|remember/i.test(y.kind)), t.delegates.join(', ') || t.yields.map((y) => y.kind).join(','));
629	  const fresh = new ThingSession(pod, { projectId: PROJECT, onAsk: scriptedOnAsk(true), verbose: true });
630	  await fresh.start();
631	  const ft = await fresh.send('remind me — is there any stretch of time coming up when I said I would be unreachable?', { timeoutMs: TURN });
632	  report.check('a fresh, historyless session recalls the August craft-fair preference', /august|craft fair|away|last week/i.test(displaysOf(ft.events) + ft.lastText), (ft.lastText || '').slice(0, 160));
633	  cp.acts.XII = { passed: report.stepPassed };
634	  saveCheckpoint(cp);
635	}
636	
637	// ═══ ACT XIII — Restart → auto-resume ═══════════════════════════════════════════════
638	if (ACTS.includes(13)) {
639	  report.step(
640	    'Act XIII — a restart does not lose the shop',
641	    'after pod.restart(), the session resumes (or re-establishes) and the spaces + app tables/pages + earlier rows all still exist and still compile',
642	  );
643	  const spacesBefore = (await pod.listSpaces(PROJECT).catch(() => ({ spaces: [] }))).spaces?.length ?? 0;
644	  const tablesBefore = ((await pod.appManifest(PROJECT).catch(() => ({}))).tables ?? []).length;
645	  await timed('Act XIII — restart the pod', async () => { await pod.restart(); await sleep(8_000); await waitPodReady(user.token).catch(() => {}); });
646	  for (let i = 0; i < 40; i++) { if (await pod.listProjects().then(() => true).catch(() => false)) break; await sleep(4_000); }
647	  const t = acc(await thing.send('you still there? what am I looking at — give me the one-line state of the shop.', { timeoutMs: TURN }));
648	  report.check('the session resumed / re-established after restart (a turn completed)', (t.llmCalls ?? 0) >= 1, `${t.llmCalls} llm calls`);
649	  const spacesAfter = (await pod.listSpaces(PROJECT).catch(() => ({ spaces: [] }))).spaces?.length ?? 0;
650	  const tablesAfter = ((await pod.appManifest(PROJECT).catch(() => ({}))).tables ?? []).length;
651	  report.check('all spaces survived the restart', spacesAfter >= spacesBefore && spacesAfter >= 4, `${spacesBefore} → ${spacesAfter}`);
652	  report.check('all app tables survived the restart', tablesAfter >= tablesBefore && tablesAfter >= 1, `${tablesBefore} → ${tablesAfter}`);
653	  const rebuilt = await pod.appBuild(PROJECT).catch(() => ({ built: false }));
654	  report.check('the app still compiles after the restart', rebuilt?.built === true, `built=${rebuilt?.built}`);
655	  cp.acts.XIII = { passed: report.stepPassed };
656	  saveCheckpoint(cp);
657	}
658	
659	// ═══ ACT XIV — A2: it actually renders (app API layer; browser done separately) ═════
660	if (ACTS.includes(14)) {
661	  report.step(
662	    'Act XIV — the served app renders real data through its OWN api layer',
663	    'the app\'s own API routes return 200 with real shape (not just the raw data API); the served root is 200 HTML with fixture-derived values. (Chrome render + console/network asserted separately by the agent via chrome-devtools.)',
664	  );
665	  await assertAppApi(report, pod, PROJECT);
666	  const page = await pod.appPage(PROJECT).catch((e) => ({ status: 0, body: String(e) }));
667	  report.check('served app root → 200 HTML', page.status === 200 && String(page.body).includes('<!doctype'), `status ${page.status}`);
668	  const rows = await allRows(pod, PROJECT);
669	  const flat = JSON.stringify(rows);
670	  const derived = ['Keramikos', 'Sibelco', 'WHL-0007', 'tenmoku', 'Cobalt'].filter((v) => new RegExp(normAlnum(v), 'i').test(normAlnum(flat)));
671	  report.check('the app data contains ≥3 real fixture-derived values (non-empty shop)', derived.length >= 3, derived.join(', '));
672	  report.note('Browser render (DOM values on screen, both chat surfaces present, zero console errors / failed fetches) is verified by the agent driving chrome-devtools — see the report narrative + screenshot path.');
673	  cp.acts.XIV = { passed: report.stepPassed };
674	  saveCheckpoint(cp);
675	}
676	
677	// ═══ verdict ════════════════════════════════════════════════════════════════════════
678	const stats = thing.stats();
679	report.step('Whole-session invariants (Edges)', 'zero UNRECOVERED eval/typecheck errors on THING\'s own turns; the SSRF echo host never reached; routing not degraded');
680	report.check('zero eval/typecheck errors across the THING session (hard fail)', stats.errors === 0, `${stats.errors} errors: ${JSON.stringify(stats).slice(0, 200)}`);
681	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
682	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
683	
684	report.save(`${RESULTS}/report.md`);
685	report.saveTrace(`${RESULTS}/trace.json`, thing);
686	cp.done = true; cp.summary = report.summary(); saveCheckpoint(cp);
687	console.log(JSON.stringify(report.summary(), null, 2));
688	clearInterval(keepalive);
689	process.exit(report.passed ? 0 : 1);
690

